import React, { useEffect, useMemo, useState } from 'react';
import Landing from './components/Landing';
import MapContainer from './components/MapContainer';
import Navbar from './components/Navbar';
import { clearAuth, loadAuth, saveAuth } from './lib/auth';

export default function App() {
  const apiBaseUrl = useMemo(() => 'http://localhost:5000', []);
  const [auth, setAuth] = useState(() => loadAuth());
  const [mode, setMode] = useState('home'); // home | give | view

  useEffect(() => {
    if (!auth) setMode('home');
  }, [auth]);

  return (
    <div className="h-full w-full">
      <Navbar
        activeKey={mode === 'view' || mode === 'give' ? 'live' : 'dashboard'}
        onNavigate={(key) => {
          if (key === 'live') setMode('view');
          if (key === 'dashboard') setMode('home');
        }}
      />

      {!auth ? (
        <Landing
          apiBaseUrl={apiBaseUrl}
          auth={auth}
          onAuthed={(data) => {
            saveAuth(data);
            setAuth(data);
          }}
          onPickMode={(m) => setMode(m)}
        />
      ) : mode === 'home' ? (
        <Landing
          apiBaseUrl={apiBaseUrl}
          auth={auth}
          onAuthed={(data) => {
            saveAuth(data);
            setAuth(data);
          }}
          onPickMode={(m) => setMode(m)}
        />
      ) : (
        <MapContainer
          apiBaseUrl={apiBaseUrl}
          auth={auth}
          defaultOpenReportModal={mode === 'give'}
          onExit={() => setMode('home')}
          onLogout={() => {
            clearAuth();
            setAuth(null);
          }}
        />
      )}
    </div>
  );
}
